/**
 * @name Path traversal in StaticResource - JAX-RS REST endpoint
 * @description StaticResource uses user-controlled path from URL to load classpath resources
 * @kind path-problem
 * @problem.severity error
 * @id java/static-resource-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module StaticResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // File constructor
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = cie.getAnArgument()
    )
  }
}

module StaticResourceFlow = TaintTracking::Global<StaticResourceConfig>;
import StaticResourceFlow::PathGraph

from StaticResourceFlow::PathNode source, StaticResourceFlow::PathNode sink
where 
  StaticResourceFlow::flowPath(source, sink) and
  (
    sink.getNode().getEnclosingCallable().getDeclaringType().getName() = "StaticResource" or
    sink.getNode().getEnclosingCallable().getDeclaringType().getName() = "ClientStubsContentSource" or
    sink.getNode().getEnclosingCallable().getDeclaringType().getName() = "LogFilesContentSource" or
    sink.getNode().getEnclosingCallable().getDeclaringType().getName() = "DownloadServlet" or
    sink.getNode().getEnclosingCallable().getDeclaringType().getName() = "LogViewerContentSource"
  )
select sink.getNode(), source, sink, "Path traversal in $@: user-controlled input from $@ reaches file/resource loading.", sink.getNode().getEnclosingCallable().getDeclaringType(), sink.getNode().getEnclosingCallable().getDeclaringType().getName(), source.getNode(), "HTTP source"

/**
 * @name Resource loading with file: scheme injection
 * @description Find ClassLoader.getResource/getResourceAsStream calls where user input could inject file: scheme prefix
 * @kind path-problem
 * @problem.severity error
 * @id java/classloader-scheme-injection
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ClassLoaderSchemeConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader resource loading
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream") or
       mc.getMethod().hasName("findResource") or mc.getMethod().hasName("findResources")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Thread ClassLoader
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Exclude paths that go through known sanitizers
    exists(MethodCall mc |
      mc.getMethod().hasName("normalize") or
      mc.getMethod().hasName("getCanonicalPath") or
      mc.getMethod().hasName("toRealPath")
    |
      node.asExpr() = mc
    )
  }
}

module ClassLoaderSchemeFlow = TaintTracking::Global<ClassLoaderSchemeConfig>;
import ClassLoaderSchemeFlow::PathGraph

from ClassLoaderSchemeFlow::PathNode source, ClassLoaderSchemeFlow::PathNode sink
where ClassLoaderSchemeFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled input from $@ flows directly to ClassLoader resource loading - could enable file: scheme injection or WEB-INF traversal.", source.getNode(), "HTTP source"

/**
 * @name DirConfigSource - property name to file path traversal
 * @description DirConfigSource maps property names to file paths - if property name contains ../ it could escape the config dir
 * @kind path-problem
 * @problem.severity error
 * @id java/dir-config-property-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module DirConfigPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Property name lookup in MicroProfile Config
    source instanceof RemoteFlowSource
    or
    // Config getValue calls that return user-influenced data
    exists(MethodCall mc |
      mc.getMethod().hasName("getValue") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.eclipse.microprofile.config", "Config") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File resolution in DirConfigSource
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasName("DirConfigSource") and
      (mc.getMethod().hasName("resolve") or
       mc.getMethod().hasName("get") and mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") or
       mc.getMethod().hasName("toAbsolutePath")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // File reading operations
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasName("DirConfigSource") and
      (mc.getMethod().hasName("readAllBytes") or 
       mc.getMethod().hasName("lines") or
       mc.getMethod().hasName("readString")) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module DirConfigPathFlow = TaintTracking::Global<DirConfigPathConfig>;
import DirConfigPathFlow::PathGraph

from DirConfigPathFlow::PathNode source, DirConfigPathFlow::PathNode sink
where DirConfigPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "DirConfigSource: user-influenced data reaches file path operation - potential path traversal if property name contains ../ sequences.", source.getNode(), "source"
